            score: 0.85,
            isPrimary: true,
            labelOrder: 1,
            selectionRationale: 'Primary category',
          },
          {
            category: 'actionable',
            subtype: null,
            confidence: 0.75,
            score: 0.75,
            isPrimary: false,
            labelOrder: 2,
            selectionRationale: 'Secondary category',
          },
        ],
        candidateScores: {},
        selectionSummary: {
          totalLabels: 2,
