          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: 'msg-001',
          categoryScores: {
            financial: {
              baseScore: 0.5,
              hardAssertionBonus: 0.3,
              strongIndicatorScore: 0.1,
              ruleScore: 0.05,
